import WidgetKit
import SwiftUI
import AppIntents
import RealityKit

struct SceneIntent: AppIntent {
    static var title: LocalizedStringResource = "3D Scene"
    @Parameter(title: "Scene Name") var sceneName: String
}

struct SceneWidget: Widget {
    var body: some WidgetConfiguration {
        AppIntentConfiguration(
            kind: "SceneWidget",
            intent: SceneIntent.self,
            provider: .static
        ) { entry in
            RealityView { content in
                if let model = try? await ModelEntity(named: entry.sceneName) {
                    content.add(model)
                }
            }
        }
    }
}

