import SwiftUI

struct NoteListView: View {
    @State private var selected: Int?
    var body: some View {
        FocusedContent(selected: $selected) {
            ForEach(0..<8) { i in
                Text("Note \(i)")
                    .background(selected == i ? Color.purple : Color.clear)
            }
        }
    }
}

